// counter accessed and mutated from many places
class Stats {
    public int counter = 0; // public mutable shared state
}

// Thread A
stats.counter++;
// Thread B — race condition
stats.counter++;

CODE_EXAMPLE:
// Shared state encapsulated and access points minimized
class Stats {
    private final AtomicInteger counter = new AtomicInteger(0);

    // Single, thread-safe mutation point
    public void increment() { counter.incrementAndGet(); }
    public int getCount() { return counter.get(); }
}

// Alternatively, pass immutable snapshots
record StatsSnapshot(int count) {}
StatsSnapshot snapshot = new StatsSnapshot(stats.getCount());

UNIT_TEST_EXAMPLE:
@Test
public void increment_isThreadSafe() throws InterruptedException {
    Stats stats = new Stats();
    int threads = 100;
    ExecutorService pool = Executors.newFixedThreadPool(threads);
    for (int i = 0; i < threads; i++) pool.submit(stats::increment);
    pool.shutdown();
    pool.awaitTermination(5, TimeUnit.SECONDS);
    assertEquals(threads, stats.getCount());
}
